/**
 * @fileoverview BilboPlayerPluginSDK - Public SDK for developing custom player visual skins and extension plugins.
 * Provides safe, cross-origin communication between the main host player and sandboxed plugin iframes.
 * Version: 1.0.0
 */

class BilboPlayerPluginSDK {
    constructor() {
        /**
         * @type {Map<string, Function[]>}
         * @private
         * Internal event bus for tracking registered listener callbacks.
         */
        this.listeners = new Map();
        
        /**
         * @type {Object}
         * @public
         * Current synchronized state of the parent player.
         */
        this.state = {
            locale: { locale: 'en-US', rtl: false },
            theme: 'light',
            vibration: null,
            player: { expanded: false },
            panes: {}
        };
        
        this._initMessageListener();
        
        // Notify the host player that the plugin iframe has loaded and is ready to receive data
        this._send('PLAYER_API_READY');
    }

    /**
     * Sends a postMessage payload to the parent window.
     * @param {string} type - System command type prefixed with 'CMD_'
     * @param {Object} [payload={}] - Optional data object
     * @param {string} [pane] - Target pane identifier
     * @private
     */
    _send(type, payload = {}, pane) {
        window.parent.postMessage({ type, payload, pane }, '*');
    }

    /**
     * Normalizes the locale payload structure to safeguard against undefined values.
     * @param {Object} payloadLocale - Raw locale data from parent
     * @returns {{locale: string, rtl: boolean}} Guaranteed locale object structure
     * @private
     */
    _normalizeLocale(payloadLocale) {
        return {
            locale: payloadLocale?.locale || 'en-US',
            rtl: !!payloadLocale?.rtl
        };
    }

    /**
     * Factory function creating the standardized base schema for independent player panes.
     * @returns {Object} Default properties for any newly initialized pane context
     * @private
     */
    _createDefaultPaneState() {
        return {
            position: null,
            prevDisabled: false,
            nextDisabled: false,
            hasQueue: false,
            repeat: 'none',
            state: 'paused',
            track: null,
            reaction: null,
            queue: { items: [], playlist: null, release: null, artist: null }
        };
    }

    /**
     * Initializes the core event gateway listening for cross-origin messages from the host.
     * @private
     */
    _initMessageListener() {
        window.addEventListener('message', (event) => {
            // Reject empty or non-object payloads for runtime stability
            if (!event.data || typeof event.data !== 'object') {
                return;
            }

            const { type, payload, pane } = event.data;

            // 1. High-Performance Audio Stream Analysis (Zero-Copy Buffer Transfer)
            if (type === 'AUDIO_DATA_FRAME' && payload?.buffer) {
                const buffer = payload.buffer;
                const dataArray = new Uint8Array(buffer);
                const targetPane = pane || 'default';

                // Dispatch raw audio frame data to the plugin's custom visualizer
                this._emitPane(targetPane, 'audioFrame', dataArray);

                // IMMEDIATELY transfer the buffer ownership back to the host window to prevent memory leaks
                window.parent.postMessage({
                    pane: targetPane,
                    type: 'AUDIO_BUFFER_BACK',
                    payload: { buffer }
                }, '*', [buffer]);
                
                return;
            }

            // 2. One-Time Master Initialization
            if (type === 'PLAYER_INIT') {
                this.state = {
                    ...this.state,
                    ...payload,
                    locale: this._normalizeLocale(payload?.locale),
                    player: { ...this.state.player, ...payload?.player },
                    panes: {}
                };

                // Safely structure and hydrate all panes provided by the host
                if (payload?.panes && typeof payload.panes === 'object') {
                    Object.keys(payload.panes).forEach(pKey => {
                        this.state.panes[pKey] = {
                            ...this._createDefaultPaneState(),
                            ...payload.panes[pKey]
                        };
                    });
                }

                this._emitGlobal('init', this.state);
                return;
            }

            // 3. Dynamic Real-time State Updates & Mutators
            if (type && payload) {
                this._updateLocalState(type, payload, pane);

                if (pane) {
                    // Fire specific key listeners (e.g., 'position')
                    this._emitPane(pane, type, payload);
                    // Fire the absolute atomic mutator event containing raw contextual keys
                    this._emitPane(pane, 'change', { type, payload, pane });
                } else {
                    this._emitGlobal(type, payload);
                }
            }
        });
    }

    /**
     * Synchronizes dynamic incoming player events into the local instance state object.
     * @param {string} type - Data property key name
     * @param {Object} payload - New property state values
     * @param {string} [pane] - Pane context if the event is scoped
     * @private
     */
    _updateLocalState(type, payload, pane) {
        if (pane) {
            // Lazy initialization backup for unannounced asynchronous pane views
            if (!this.state.panes[pane]) {
                this.state.panes[pane] = this._createDefaultPaneState();
            }
            
            const currentPane = this.state.panes[pane];
            switch (type) {
                case 'hasQueue': currentPane.hasQueue = payload.value; break;
                case 'nextDisabled': currentPane.nextDisabled = payload.value; break;
                case 'prevDisabled': currentPane.prevDisabled = payload.value; break;
                case 'repeat': currentPane.repeat = payload.value; break;
                case 'state': currentPane.state = payload.state; break;
                case 'position': currentPane.position = payload.position; break;
                case 'track': currentPane.track = payload.track; break;
                case 'reaction': currentPane.reaction = payload.reaction; break;
                case 'queue': 
                    currentPane.queue = {
                        items: payload.items || [],
                        playlist: payload.playlist || null,
                        release: payload.release || null,
                        artist: payload.artist || null
                    };
                    break;
            }
        } else {
            switch (type) {
                case 'theme': this.state.theme = payload.theme; break;
                case 'vibration': this.state.vibration = payload.vibration; break;
                case 'player': 
                    if (!this.state.player) this.state.player = {};
                    this.state.player.expanded = payload.expanded; 
                    break;
                case 'locale': 
                    this.state.locale = this._normalizeLocale(payload);
                    break;
            }
        }
    }

    /**
     * Dispatches callbacks attached to global system states.
     * @private
     */
    _emitGlobal(internalEvent, data) {
        if (this.listeners.has(internalEvent)) {
            this.listeners.get(internalEvent).forEach(cb => cb(data));
        }
    }

    /**
     * Dispatches callbacks attached to isolated screen scopes (panes).
     * @private
     */
    _emitPane(pane, internalEvent, data) {
        const paneEventKey = `${pane}:${internalEvent}`;
        if (this.listeners.has(paneEventKey)) {
            this.listeners.get(paneEventKey).forEach(cb => cb(data));
        }
    }

    // --- PUBLIC DEVELOPER API INTERFACE ---

    /**
     * Registers an event listener callback for player updates.
     * @param {string} event - Event name ('init', 'theme', 'locale', 'audioFrame', 'change', or atomics like 'position')
     * @param {Function} callback - Execution block triggered on event dispatch
     * @param {string} [pane='default'] - Targeted screen scope pane
     * @public
     */
    on(event, callback, pane = 'default') {
        const globalEventMap = {
            'init': 'init',
            'theme': 'theme',
            'locale': 'locale',
            'vibration': 'vibration',
            'player': 'player'
        };

        let eventKey = globalEventMap[event] ? globalEventMap[event] : `${pane}:${event}`;

        if (!this.listeners.has(eventKey)) {
            this.listeners.set(eventKey, []);
        }

        this.listeners.get(eventKey).push(callback);
    }

    /**
     * Removes a specific event listener callback.
     * @param {string} event - Registered event name
     * @param {Function} callback - Reference to the callback function to remove
     * @param {string} [pane='default'] - Screen scope pane context
     * @public
     */
    off(event, callback, pane = 'default') {
        const globalEventMap = {
            'init': 'init',
            'theme': 'theme',
            'locale': 'locale',
            'vibration': 'vibration',
            'player': 'player'
        };

        let eventKey = globalEventMap[event] ? globalEventMap[event] : `${pane}:${event}`;

        if (this.listeners.has(eventKey)) {
            const callbacks = this.listeners.get(eventKey);
            const index = callbacks.indexOf(callback);
            if (index !== -1) {
                callbacks.splice(index, 1);
            }
            if (callbacks.length === 0) {
                this.listeners.delete(eventKey);
            }
        }
    }

    /**
     * Requests the host player to resume audio playback.
     * @param {string} [pane='default'] - Screen scope pane target
     */
    play(pane = 'default') { 
        this._send('CMD_PLAY', null, pane); 
    }

    /**
     * Requests the host player to pause audio playback.
     * @param {string} [pane='default'] - Screen scope pane target
     */
    pause(pane = 'default') { 
        this._send('CMD_PAUSE', null, pane); 
    }
    
    /**
     * Requests the host player to seek to a precise timestamp position.
     * @param {number} ms - Accurate destination timestamp in milliseconds
     * @param {string} [pane='default'] - Screen scope pane target
     */
    seek(ms, pane = 'default') {
        if (typeof ms !== 'number') {
            throw new Error('[SDK] Seek position timestamp value must be a number (milliseconds)');
        }
        this._send('CMD_SEEK', { time: ms }, pane);
    }

    /**
     * Skips forward to the next audio track in queue sequence.
     * @param {string} [pane='default'] - Screen scope pane target
     */
    next(pane = 'default') { 
        this._send('CMD_NEXT', null, pane); 
    }

    /**
     * Skips backward to the previous audio track in queue sequence.
     * @param {string} [pane='default'] - Screen scope pane target
     */
    prev(pane = 'default') { 
        this._send('CMD_PREV', null, pane); 
    }

    /**
     * Requests the parent interface to open the native track metadata options dialog (kebab overlay).
     */
    openTrackKebab() { 
        this._send('CMD_OPEN_TRACK_KEBAB'); 
    }

    /**
     * Requests the parent interface to overlay or open the global active playlist window.
     */
    openPlaylist() { 
        this._send('CMD_OPEN_PLAYLIST'); 
    }

    /**
     * Dispatches user reactions (Like/Dislike evaluation tags) to the host backend.
     * @param {null|'LIKE'|'DISLIKE'|''} reaction - The evaluation rating keyword identifier
     * @param {string} [pane='default'] - Screen scope pane target
     */
    reaction(reaction, pane = 'default') {
        if ([null, 'LIKE', 'DISLIKE', ''].indexOf(reaction) === -1) {
            return;
        }
        this._send('CMD_REACTION', { reaction }, pane);
    }

    /**
     * Configures loop/repetition states for player playback queues.
     * @param {'none'|'queue'|'track'} repeat - Mode configuration keyword
     * @param {string} [pane='default'] - Screen scope pane target
     */
    repeat(repeat, pane = 'default') {
        if (['none', 'queue', 'track'].indexOf(repeat) === -1) {
            return;
        }
        this._send('CMD_REPEAT', { repeat }, pane);
    }

    /**
     * Jump-starts audio playback to a precise indexed item situated inside the active QueuePreview payload.
     * @param {number} index - Absolute zero-based target track array index inside queue layout
     * @param {string} [pane='default'] - Screen scope pane target
     */
    playQueueIndex(index, pane = 'default') {
        this._send('CMD_PLAY_QUEUE_INDEX', { index }, pane);
    }

    /**
     * Declares custom visibility states overriding the native parent container layout widgets.
     * Used by immersive extensions taking over standard HTML progress trackers or carousel image cards.
     * @param {Object} config - Partial or complete map configuration object properties overrides
     */
    setUiConfig(config) {
        if (typeof config !== 'object') {
            throw new Error('[SDK] Custom layout config descriptor metadata properties block must be an object');
        }
        this._send('CMD_UPDATE_UI_CONFIG', config);
    }

    /**
     * Requests the parent interface to expand the player view (e.g., transition to full-screen mode).
     */
    expand() { 
        this._send('CMD_EXPAND'); 
    }

    /**
     * Requests the parent interface to collapse the player view (e.g., transition to minimized/compact mode).
     */
    collapse() { 
        this._send('CMD_COLLAPSE'); 
    }
}

// Export singleton engine instance context for micro-frontend module deployments
export const playerSdk = new BilboPlayerPluginSDK();
